import React, { createContext, useState, useContext, useEffect } from 'react';

const VehicleContext = createContext(null);

export const useVehicles = () => {
  const context = useContext(VehicleContext);
  if (!context) {
    throw new Error('useVehicles must be used within a VehicleProvider');
  }
  return context;
};

export const VehicleProvider = ({ children }) => {
  // Load vehicles from localStorage or use default empty array
  const [vehicles, setVehicles] = useState(() => {
    const storedVehicles = localStorage.getItem('vehicles');
    if (storedVehicles) {
      return JSON.parse(storedVehicles);
    }
    return []; // Start empty as requested
  });

  // Save to localStorage whenever vehicles change
  useEffect(() => {
    localStorage.setItem('vehicles', JSON.stringify(vehicles));
  }, [vehicles]);

  const addVehicle = (vehicle) => {
    const newVehicle = {
      ...vehicle,
      id: Date.now(),
      status: vehicle.status || 'active'
    };
    setVehicles(prev => [...prev, newVehicle]);
  };

  const updateVehicle = (id, updatedVehicle) => {
    setVehicles(prev => prev.map(v => v.id === id ? { ...updatedVehicle, id } : v));
  };

  const deleteVehicle = (id) => {
    setVehicles(prev => prev.filter(v => v.id !== id));
  };

  const toggleVehicleStatus = (id) => {
    setVehicles(prev => prev.map(v => 
      v.id === id ? { ...v, status: v.status === 'active' ? 'inactive' : 'active' } : v
    ));
  };

  const getActiveVehicles = () => {
    return vehicles.filter(v => v.status === 'active');
  };

  const value = {
    vehicles,
    setVehicles,
    addVehicle,
    updateVehicle,
    deleteVehicle,
    toggleVehicleStatus,
    getActiveVehicles
  };

  return (
    <VehicleContext.Provider value={value}>
      {children}
    </VehicleContext.Provider>
  );
};

export default VehicleContext;
